This is the config we're running: 
```
group yolo {
    neighbor 10.60.2.2 {
        local-as 65001;
        local-address 10.60.2.100;
        group-updates true;
        peer-as 64610;

        family {
            ipv4 unicast;
        }

        capability swag {
            operational enable;
            multi-session disable;
            route-refresh enable;
            graceful-restart 30;
            add-path send/receive;
            asn4 disable;
        }

        process check-nginx_1 {
            run "/etc/exabgp/check.sh -T nginx -H nginx1.example.com/status -t 4 -w nginx_1";
        }

        static {
            route 172.29.29.128/26 next-hop 10.60.32.17 med 100 path-information 0.0.0.149 watchdog nginx_1;
        }
        
        process check-nginx_2 {
            run "/etc/exabgp/check.sh -T nginx -H nginx2.example.com/status -t 10 -w nginx_2";
